      options: [{ id: `A`, text: `<em>c</em> = 14<em>x</em> + 31` }, { id: `B`, text: `<em>c</em> = 31<em>x</em> + 14` }, { id: `C`, text: `<em>c</em> = 31<em>x</em>` }, { id: `D`, text: `<em>c</em> = 45<em>x</em>` }],
